import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import axios from 'axios';
import { UploadCloud, Info, Loader2 } from 'lucide-react';
import { generarNombreImagen } from '../utils/helpers';

const CargaMasiva = ({ localId, onComplete }) => {
  const [loading, setLoading] = useState(false);

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (!file || !localId) return;

    setLoading(true);
    const reader = new FileReader();

    reader.onload = async (event) => {
      try {
        const bstr = event.target.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);

        const productosProcesados = data.map(prod => ({
          producto: `${prod.tipo} ${prod.marca} ${prod.contenido}`,
          categoria: prod.categoria || 'Almacén',
          precioNuevo: Number(prod.precioNuevo),
          precioViejo: Number(prod.precioViejo),
          stock: Number(prod.stock || 0),
          peso: Number(prod.peso || 0),
          fechaVencimiento: prod.fechaVencimiento,
          publicId: generarNombreImagen(prod.tipo, prod.marca, prod.contenido),
          local: localId
        }));

        await axios.post(`${process.env.REACT_APP_API_URL}/api/ofertas/bulk`, {
          productos: productosProcesados,
          localId: localId
        });

        alert(`✅ Éxito: ${data.length} productos vinculados a la carpeta Productos.`);
        if (onComplete) onComplete();
      } catch (error) {
        alert("❌ Error. Columnas requeridas: tipo, marca, contenido, categoria, precioNuevo, precioViejo, stock, fechaVencimiento");
      } finally {
        setLoading(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div style={{ background: '#f0f9ff', padding: '15px', borderRadius: '15px', border: '1px solid #bae6fd', marginBottom: '20px' }}>
      <label style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', cursor: 'pointer', padding: '12px', background: 'white', borderRadius: '10px', border: '2px dashed #7dd3fc', opacity: loading ? 0.5 : 1 }}>
        {loading ? <Loader2 className="animate-spin" /> : <UploadCloud size={24} color="#0284c7" />}
        <span style={{ fontWeight: 'bold', fontSize: '0.85rem' }}>Importar Excel a Cloudinary</span>
        <input type="file" accept=".xlsx, .xls" onChange={handleFileUpload} style={{ display: 'none' }} disabled={loading} />
      </label>
    </div>
  );
};

export default CargaMasiva;
